document.addEventListener("DOMContentLoaded", function() {
    // 1. Smooth Page Transitions
    const links = document.querySelectorAll('a[href]:not([target="_blank"]):not([href^="#"])');
    links.forEach(link => {
        link.addEventListener('click', function(e) {
            // Only local links
            if (this.hostname === window.location.hostname && !e.ctrlKey && !e.metaKey) {
                e.preventDefault();
                const target = this.href;
                document.body.style.transition = 'opacity 0.4s ease';
                document.body.style.opacity = '0';
                setTimeout(() => {
                    window.location.href = target;
                }, 400);
            }
        });
    });

    // 3. Scroll-to-Top Button
    const scrollTopBtn = document.createElement('button');
    scrollTopBtn.innerHTML = '<i class="fa-solid fa-arrow-up"></i>';
    scrollTopBtn.className = 'btn btn-primary rounded-circle shadow-lg position-fixed bottom-0 end-0 m-4 d-none';
    scrollTopBtn.style.zIndex = '9999';
    scrollTopBtn.style.width = '50px';
    scrollTopBtn.style.height = '50px';
    scrollTopBtn.style.transition = 'all 0.3s ease';
    document.body.appendChild(scrollTopBtn);

    window.addEventListener('scroll', () => {
        if (window.scrollY > 500) {
            scrollTopBtn.classList.remove('d-none');
            scrollTopBtn.style.opacity = '1';
        } else {
            scrollTopBtn.style.opacity = '0';
            setTimeout(() => { if(window.scrollY <= 500) scrollTopBtn.classList.add('d-none'); }, 300);
        }
    });

    scrollTopBtn.addEventListener('click', () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    });
});

